// WobbleDrag.tsx
import React from 'react';
import {StyleSheet, View} from 'react-native';
import {GestureDetector, Gesture} from 'react-native-gesture-handler';
import Animated, {useSharedValue, useAnimatedStyle, withSpring} from 'react-native-reanimated';
export function WobbleDrag({children}: {children: React.ReactNode}) {
  const x = useSharedValue(0); const y = useSharedValue(0);
  const pan = Gesture.Pan().onUpdate(e => { x.value = e.translationX; y.value = e.translationY; }).onEnd(() => { x.value = withSpring(0, {damping: 4, stiffness: 120, mass: 1.2}); y.value = withSpring(0, {damping: 4, stiffness: 120, mass: 1.2}); });
  const style = useAnimatedStyle(() => ({transform: [{translateX: x.value}, {translateY: y.value}]}));
  return (<GestureDetector gesture={pan}><Animated.View style={style}>{children}</Animated.View></GestureDetector>);
}

