import React, {useEffect} from 'react';
import {StyleSheet, View, Text} from 'react-native';
import {Canvas, Rect, Line, vec} from '@shopify/react-native-skia';
import {useSharedValue, withTiming, useDerivedValue} from 'react-native-reanimated';
export function BulletChart({actual, target, max, width, height = 28}: {actual: number; target: number; max: number; width: number; height?: number}) {
  const p = useSharedValue(0);
  useEffect(() => { p.value = withTiming(1, {duration: 700}); }, []);
  const barW = useDerivedValue(() => (actual/max) * width * p.value);
  const targetX = (target/max) * width;
  return (<View><Canvas style={{width, height}}><Rect x={0} y={0} width={width} height={height} color='#1C1C1E'/><Rect x={0} y={0} width={barW} height={height} color='#0A84FF'/><Line p1={vec(targetX, 0)} p2={vec(targetX, height)} color='#FF453A' strokeWidth={2}/></Canvas><Text style={s.label}>{actual} / {target} (target)</Text></View>);
}
const s = StyleSheet.create({label:{color:'#8E8E93', fontSize:11, marginTop:4}});

