import React, {useState, useCallback} from 'react';
import MapView, {Marker} from 'react-native-maps';
import * as Location from 'expo-location';
import {StyleSheet, View, Text} from 'react-native';
export function PinDropGeocode() {
  const [coord, setCoord] = useState<{latitude: number; longitude: number} | null>(null);
  const [address, setAddress] = useState<string>('');
  const onPress = useCallback(async (e: any) => { const c = e.nativeEvent.coordinate; setCoord(c); const r = await Location.reverseGeocodeAsync(c); setAddress(r[0]?.street ?? ''); }, []);
  return (<View style={{flex:1}}><MapView style={StyleSheet.absoluteFill} onPress={onPress}>{coord && <Marker coordinate={coord}/>}</MapView><View style={s.box}><Text style={s.text}>{address}</Text></View></View>);
}
const s = StyleSheet.create({box:{position:'absolute', top:60, left:16, right:16, padding:12, backgroundColor:'rgba(0,0,0,0.7)', borderRadius:8}, text:{color:'#fff'}});

