// SlideToConfirm.tsx
import React from 'react';
import {StyleSheet, View, Text} from 'react-native';
import {GestureDetector, Gesture} from 'react-native-gesture-handler';
import Animated, {useSharedValue, useAnimatedStyle, withSpring, runOnJS} from 'react-native-reanimated';
import * as Haptics from 'expo-haptics';
export function SlideToConfirm({onConfirm, label = 'Slide to send'}: {onConfirm: () => void; label?: string}) { const x = useSharedValue(0); const trackW = 280; const knob = 50; const max = trackW - knob - 8; const commit = () => { Haptics.notificationAsync(Haptics.NotificationFeedbackType.Success); onConfirm(); }; const pan = Gesture.Pan().onUpdate(e => { x.value = Math.max(0, Math.min(max, e.translationX)); }).onEnd(() => { if (x.value >= max - 10) { runOnJS(commit)(); x.value = withSpring(0); } else { x.value = withSpring(0); }}); const style = useAnimatedStyle(() => ({transform: [{translateX: x.value}]})); return (<View style={[s.track, {width: trackW}]}><Text style={s.label}>{label}</Text><GestureDetector gesture={pan}><Animated.View style={[s.knob, style]}><Text style={s.knobIcon}>{'→'}</Text></Animated.View></GestureDetector></View>); }
const s = StyleSheet.create({track:{height:58, backgroundColor:'#1C1C1E', borderRadius:29, padding:4, justifyContent:'center'}, label:{position:'absolute', alignSelf:'center', color:'#8E8E93'}, knob:{width:50, height:50, borderRadius:25, backgroundColor:'#0A84FF', alignItems:'center', justifyContent:'center'}, knobIcon:{color:'#fff', fontSize:24}});

