import React, {useState, useEffect} from 'react';
import {StyleSheet, View, Text, Pressable} from 'react-native';
import {FlashList} from '@shopify/flash-list';
import * as Contacts from 'expo-contacts';
export function ContactPicker({onSelect}: {onSelect: (c: any) => void}) { const [contacts, setContacts] = useState<any[]>([]); useEffect(() => { (async () => { const {status} = await Contacts.requestPermissionsAsync(); if (status !== 'granted') return; const {data} = await Contacts.getContactsAsync({fields: [Contacts.Fields.PhoneNumbers]}); setContacts(data); })(); }, []); return (<FlashList data={contacts} estimatedItemSize={56} keyExtractor={c => c.id ?? ''} renderItem={({item}) => (<Pressable onPress={() => onSelect(item)} style={s.row}><Text style={s.name}>{item.name}</Text></Pressable>)}/>); }
