// PulsingBadge.tsx
import React, {useEffect, useRef} from 'react';
import {StyleSheet, View} from 'react-native';
import Animated, {useSharedValue, useAnimatedStyle, withSequence, withSpring} from 'react-native-reanimated';
export function PulsingBadge({count}: {count: number}) { const scale = useSharedValue(1); const prevRef = useRef(count); useEffect(() => { if (count > prevRef.current) scale.value = withSequence(withSpring(1.4, {damping: 10}), withSpring(1, {damping: 14})); prevRef.current = count; }, [count]); const style = useAnimatedStyle(() => ({transform: [{scale: scale.value}]})); return count > 0 ? <Animated.View style={[s.badge, style]}/> : null; }
const s = StyleSheet.create({badge:{width:8, height:8, borderRadius:4, backgroundColor:'#FF453A'}});

